export interface Profile {
  id: string
  name: string
}

export function label(profile: Profile) {
  return profile.name
}

import { expect, test } from 'bun:test'
import { label, type Profile } from '../src/profile'

test('labels a profile with its name', () => {
  const profile: Profile = { id: 'u_123', name: 'Ada Lovelace' }
  expect(label(profile)).toBe('Ada Lovelace')
})
